sql.where:
l.customerid = #{customerId}
AND l.deletedat IS NULL
AND l.deviceid = #{deviceId}
AND l.devicenumber ILIKE '%' || #{deviceNumber} || '%'
AND l.ownername ILIKE '%' || #{ownerName} || '%'
AND l.assetstatus = #{assetStatus}
AND l.devicecondition = #{deviceCondition}
AND l.batterycondition = #{batteryCondition}
AND l.createdat >= #{dateFrom}
AND l.createdat <= #{dateTo}

mapper.select:
SELECT l.*, u.name AS loggedbyusername FROM plugin_itam_log l LEFT JOIN users u ON u.id = l.loggedbyuserid
ORDER BY l.createdat DESC
LIMIT #{pageSize} OFFSET (#{pageNum} - 1) * #{pageSize}
